    "quotePage": {
      "en": "BenchCouncil AI100: Expert systems / DENDRAL",
      "zh": "BenchCouncil AI100：专家系统 / DENDRAL"
    },
    "commentarySections": [
      {
        "label": {
          "en": "Historical Background",
          "zh": "历史背景"
        },
        "html": {
          "en": "General-purpose problem solving was not enough for hard scientific tasks. DENDRAL showed that carefully encoded expertise could focus search.",
          "zh": "通用问题求解不足以处理困难科学任务。DENDRAL 表明，精心编码的专业知识可以聚焦搜索。"
        }
      },
      {
        "label": {
          "en": "Core Idea",
          "zh": "核心思想"
        },
        "html": {
          "en": "The system generated candidate molecular structures and rejected impossible ones using chemical constraints.",
          "zh": "系统生成候选分子结构，并用化学约束排除不可能的候选。"
        }
      },
      {
        "label": {
          "en": "Long-Term Legacy",
          "zh": "长期影响"
        },
        "html": {
          "en": "Experts generally treat DENDRAL as one of the first convincing demonstrations that domain knowledge could make AI useful. Its long-term legacy is the expert-system and knowledge-engineering tradition in chemistry, medicine, and enterprise decision support.",
          "zh": "专家通常把 DENDRAL 视为最早有力证明领域知识能让 AI 变得有用的系统之一。它的长期影响在于推动了化学、医学和企业决策支持中的专家系统与知识工程传统。"
        }
      }
    ],
