    "quotePage": {
      "en": "BenchCouncil AI100: Dimensionality reduction / t-SNE",
      "zh": "BenchCouncil AI100：降维 / t-SNE"
    },
    "commentarySections": [
      {
        "label": {
          "en": "Historical Background",
          "zh": "历史背景"
        },
        "html": {
          "en": "Researchers needed intuitive ways to inspect embeddings, digits, gene expression, and other high-dimensional data.",
          "zh": "研究者需要直观方法检查嵌入、数字、基因表达等高维数据。"
        }
      },
      {
        "label": {
          "en": "Core Idea",
          "zh": "核心思想"
        },
        "html": {
          "en": "t-SNE preserves local neighbor probabilities while using a t distribution to reduce crowding in the 2D map.",
          "zh": "t-SNE 保持局部邻域概率，并用 t 分布减少二维图中的拥挤问题。"
        }
      },
      {
        "label": {
          "en": "Long-Term Legacy",
          "zh": "长期影响"
        },
        "html": {
          "en": "Experts generally treat t-SNE as a powerful exploratory visualization tool that must be interpreted carefully. Its long-term legacy is making high-dimensional embeddings visually inspectable, while teaching users that cluster maps can be persuasive but not definitive evidence.",
          "zh": "专家通常把 t-SNE 视为强大的探索性可视化工具，但也强调必须谨慎解读。它的长期影响在于让高维嵌入变得可视化可检查，同时提醒用户簇图有说服力但不是决定性证据。"
        }
      }
    ],
